const Q_GEOGRAPHY_2019_MODEL_I=[{"id": "objective>Geography>2019 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most suitable statistical diagram to show spatial distribution of production is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">divided circle </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dot map</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pie chart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">line graph</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ground survey aims to make accurate map of a part of the earth's surface. <br/> Dot map is very widely used for showing distribution e.g population. It is used to absolute figures, e.g a dot may represent 3,000 people on the map.</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2019 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The variable which is both a control and an element of weather and climate is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wind </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Air mass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rainfall</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wind - It influences both rainfall and temperature , it is itself one of the elements of weather and climate.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2019 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The relative dryness of the Horn Africa is due to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The dominance of cold currents in the region.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The distance from the belt of tropical cyclones.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Its closeness to the high ranges of East Africa.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The shape and direction of the shoreline</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shape and direction of the shoreline ensure that most wind blow off-shove leading to dryness.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2019 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The development of a climax vegetation in the Savannah belt of Nigeria is disturbed mainly by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lumbering </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mining </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bush burning </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Animal grazing</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bush burning has become an incessant seasonal problem facing Savanna vegetation in the Savannah belt of Nigeria. <br/> People in the Savannah belt of Nigeria destroy the bushes annually while trying to kill games animals by setting them on fire.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2019 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most densely populated city which is also the capital of a country in Africa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dakar </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cape Town</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abuja </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cairo</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cairo is the second largest city, after Johannesburg, in Africa. The Lower Nile valley in Cairo is one of the densely populated areas of the world.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2019 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country well known for the production of Copper in Africa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ghana</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Republic of Benin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zambia </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Egypt</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zambia has one of the world's largest reserves of Copper. Copper accounts for more than 97% of Zambia's export value. The zambia copper belt is an extension of the Shaba Copper belt of Democratic Republic of Congo.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2019 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The areas in Nigeria where temperate crops may be grown include </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Jos Plateau and Mambilla Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mandara Mountains and Biu Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Apata Hills and Effon Ridge </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oban Hills and Yoruba Highlands</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Jos Plateau and Mambilla Plateau modify the local climate which makes the climate relatively cooler than it is least expected. This climatic condition favours the growth of wheat.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2019 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most capital-intensive sector of Nigeria economy to day is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mining </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trading</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The route-ways (road, rail, water) need constant maintenance and the facilities (seaport, airports as well as the spare parts which are costly to acquire and maintain. <br/> Transportation is a very large sector. It covers the different modes of transportation such as air, water, road and rail. The cost of maintaining the routes of these modes of transportation is expensive. Also the facilities such as seaport and airport is costly to maintain, same with the spare parts. <br/> The cost of also building an airplane or ship is really expensive. <br/>  <br/> Other capital intensive companies includes the Energy companies, Automobile manufacturing companies etc</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2019 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Examples of fold mountains in Africa are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Drakensberg Mountains and Mount Cameroun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Atlas Mountains and Mount Kenya </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cape Ranges and Atlas Mountains </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mont Kilimanjaro and Atlas Mountains </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Atlas Mountains of Morocco in North Africa and Cape ranges of West Africa are good examples of Fold Mountains in Africa.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2019 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A good example of cuesta landscape in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Biu plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Udi Hills </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yoruba Hills </div>", "<div style=\"font-family:Cambria;font-size:17px;\">North Central Highlands </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cuesta is a hill or ridge with a gentle slope on one side, and a steep slope on the other. In Nigeria, Udi Hills is a good example of a cuesta landscape. The other options do not represent cuesta landscapes.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2019 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The prairies of North America are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">montane grasslands </div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperate grasslands </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropical grasslands </div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperate grassland</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The prairies of North America is recognized for wheat production. Wheat is best supported by temperate climate. In other words, they are temperate grasslands.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2019 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lakes kivu and Malawi are related in that they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">attract a large number of tourists.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lie in the Northern Hemisphere </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rift valley lakes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">are crater lakes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The East African Rift Valley system is 4800km long stretching from East Africa through the Red Sea to Syria. It contains the following lakes: Lake Tangayika, Lake Edward, Lake Nweru and Lake Malawi.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2019 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Automobile Industries that are essentially assembly plants are found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">West Africa </div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Western Europe </div>", "<div style=\"font-family:Cambria;font-size:17px;\">North East USA</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is because the parts are imported from advanced countries and assembled in West Africa.  For instance, we have Peugeot Assembly Plant in Kaduna, Nigeria in West Africa .</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2019 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria recently entered into trade agreements in petroleum products and gas with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all West African countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">most countries of North Africa </div>", "<div style=\"font-family:Cambria;font-size:17px;\">some West African countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">all African countries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria is Africa's largest producer of Petroleum which also has a large natural gas deposit and the ECOWAS Treaty opens the West African market to Nigeria. Nigeria has agreed to supply petroleum products and gas to some West African countries, e.g Ghana, Republic of Benin, etc.</div>", "topic": "REGIONAL GEOGRAPHY : INTERNATIONAL ECONOMIC COOPERATION IN WEST AFRICA ECOWAS"}, {"id": "objective>Geography>2019 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The group of hardwoods that are suitable for railway sleepers in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gmelina, teak and spruce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">obeche, mahogamy and pine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pine, fir and mahogamy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mahogamy, obeche and iroko</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mahogamy, Obeche, Iroko, etc, are hard woods which can resist early decay. They are tropical hardwoods suitable for the construction of railway steepers.</div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>2019 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sex ratio of any population may be affected by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mortality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morbidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fertility</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The young able-bodied men usually embark on migration for better economic opportunities. Thus, there will be more females than males.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2019 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An igneous rock with distinct grains of mica, fieldspar and quartz is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">schist </div>", "<div style=\"font-family:Cambria;font-size:17px;\">basalt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rhyolite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">granite </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Granite is an igneous rock that is characterized by its coarse-grained texture and the presence of distinct grains of mica, feldspar, and quartz. Schist is a metamorphic rock, basalt is a fine-grained igneous rock, and rhyolite is an extrusive igneous rock, none of which are characterized by the presence of distinct grains of mica, feldspar, and quartz.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2019 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a landform produced by glaciation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a cirque </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a sand-dune</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an ox-bow lake </div>", "<div style=\"font-family:Cambria;font-size:17px;\">horizon </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is because only cirque is an erosion landform of glaciation. Others are not. A cirque is produced by glacial erosion. It is a depression where neve accumulates.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2019 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Stevenson's screen is raised about one meter above the ground  in order to avoid </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rain drops entering it </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the influence of strong winds </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the effects of nearby trees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the heat from the ground</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To enable the thermometer have an accurate temperature reading and avoid radiation. It is raised 1.2 metres above the ground to avoid the heat from the ground.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2019 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In surveying, fixed obstacles are best dealt with by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">avoiding them </div>", "<div style=\"font-family:Cambria;font-size:17px;\">using abney level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">removing them </div>", "<div style=\"font-family:Cambria;font-size:17px;\">laying offsets</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fixed obstacles are best dealt with by laying offsets i.e, measuring the perpendicular distances to the particular obstacles at intervals from the chain.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2019 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The merging together of a number of urban settlements will produce a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Conurbation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nucleated settlement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Linear settlement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Suburb </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The merging together of a number of urban settlements will produce a Conurbation. A conurbation is a region comprising a number of cities, large towns, and other urban areas that, through population growth and physical expansion, have merged to form one continuous urban or industrially developed area. Nucleated, linear settlements and suburbs are types of settlements but they do not result from the merging of multiple urban settlements.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2019 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The world's leading producer of cocoa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ecuador </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ghana</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brazil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ghana produces more than countries in the options given. Ghana produces over 30% of World's cocoa. Nigeria produces about 20% and Brazil produces about 30%.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2019 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs of cities have both seaport and international airport?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rio de Janeiro and Johannesburg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lagos and San Francisco</div>", "<div style=\"font-family:Cambria;font-size:17px;\">New York and Warri</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kampala and Mombasa</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lagos is commercial centre in Nigeria and San Francisco is a coastal settlement in North America. Each of the two settlements by virtue of their coastal location has a seaport and an international airport.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2019 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process by which organic matter is decomposed and synthesized to form part of the soil is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">humification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mineralization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">laterization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrification</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process by which organic matter is decomposed and synthesized to form part of the soil is known as humification. Humification is the process of transformation of raw organic matter into humus, a stable organic material that is a major component of soil.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2019 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the standard time of a country is GMT + 1hr, which longitude's local time is adopted by the country?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60°W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60°E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15°W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15°E</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Places East of the Prime Meridian are ahead and, as such, gain time; time difference is added 1° equals 4 minutes, hence, 1 hour will be 15° obtained by dividing 60 minutes by 4 minutes.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2019 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highest category of rural settlement is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Village </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hamlet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Homestead </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hut</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In terms of size and complexity, the highest category of rural settlement is the village. A village is larger than a hamlet, homestead, or hut, and typically has more facilities and services. Therefore, the correct answer is Village.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2019 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most common greenhouse gas in the atmosphere is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorofluorocarbon </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(ii)oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen bromide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (iv) oxide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most common greenhouse gas in the atmosphere is carbon dioxide (CO2), also known as carbon (iv) oxide. Greenhouse gases trap heat in the atmosphere, contributing to the greenhouse effect and global warming. Therefore, the correct answer is carbon (iv) oxide.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2019 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">British foreign investments are concentrated in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Commonwealth countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Developed Countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">EU Countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ECOWAS Countries</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commonwealth countries refer to countries formerly colonized by Great Britain most of which still have attachment to Britain.</div>", "topic": "REGIONAL GEOGRAPHY : INTERNATIONAL ECONOMIC COOPERATION IN WEST AFRICA ECOWAS"}, {"id": "objective>Geography>2019 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The rock that is igneous is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rock that is igneous is N - The rock is batholiths which is a massive dome found beneath the earth's surface (where Volcanic had taken place).</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2019 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Limestone can be identified within the area marked </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Limestone is associated with joints and bedding planes which encourages the development of skinholes. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2019 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Urban and Rural Settlements are differentiated by their </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">population and function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">function and location </div>", "<div style=\"font-family:Cambria;font-size:17px;\">function only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Urban and Rural Settlements are differentiated by their population and function. Urban areas typically have a higher population density and vast human features in comparison to areas that are considered rural. The function of the settlement, whether it's primarily residential, commercial, or industrial, also plays a role in differentiating between urban and rural settlements.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2019 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Ruhr coalfield is located in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Russia </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Germany</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the USA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Canada </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Ruhr coalfield is located in Germany. It is the largest coal deposit in Germany and has been a significant source of coal, coke, and steel for the country. The Ruhr region was formerly an industrial powerhouse, with many heavy industries using the coal from the Ruhr coalfield.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2019 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The exploitation of timber in equatorial Africa causes </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soil erosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">environmental pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less rainfall run-off</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high cost of foreign products </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The leads to deforestation which exposes the soils to direct heavy downpours resulting into washing away of the top soils.</div>", "topic": "PRATICAL GEOGRAPHY II : LUMBERING IN EQUATORIAL AFRICA"}, {"id": "objective>Geography>2019 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soil texture is determined primarily by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profile horizons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">major components </div>", "<div style=\"font-family:Cambria;font-size:17px;\">particle sizes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nutrient status </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soil texture is primarily determined by the size of the particles that make up the soil. These particles are typically classified as sand, silt, or clay, and the proportion of each in a soil sample determines its texture. For example, a soil with a high proportion of sand particles will have a sandy texture.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2019 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A desert country which has high population density supported by irrigation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kuwait </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sudan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Namibia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Egypt</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The lower Nile valley lies in the desert but due to heavy irrigation projects embarked upon, the area attracts high population concentration.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2019 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The speed and capacity of a train are influenced by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">length of the railway line </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the edge of the railway line </div>", "<div style=\"font-family:Cambria;font-size:17px;\">width of the railway gauge </div>", "<div style=\"font-family:Cambria;font-size:17px;\">depth of the railway line </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The speed and capacity of a train are influenced by the width of the railway gauge (narrow, standard and broad gauges).</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2019 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors may lead to an area being densely populated?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">High plateaux </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lowland plains </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rugged mountains </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Active volcanoes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lowland plains are more likely to be densely populated. This is because they are generally easier to build on, have more fertile soil for agriculture, and are more accessible for transportation compared to high plateaux, rugged mountains, and active volcanoes.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2019 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of argillaceous rock is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chalk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coat </div>", "<div style=\"font-family:Cambria;font-size:17px;\">graphite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shale</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chalk is an example of argillaceous rock others are not.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2019 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A weather element controlled mainly by latitude is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cloud cover</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A weather element controlled mainly by latitude is temperature. This is due to the movement of the overhead sun. Within the tropics, the sun usually overheads and hence, the temperature is always high but beyond the tropics, the sun is never overhead and so, the temperature is low.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2019 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A poor settlement on the edge of a city is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shanty town</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ghetto</div>", "<div style=\"font-family:Cambria;font-size:17px;\">new town </div>", "<div style=\"font-family:Cambria;font-size:17px;\">slum</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A poor settlement on the edge of a city is known as a shanty town. Shanty towns are typically characterized by substandard housing and squalor, and are often built on the outskirts of cities. They are usually inhabited by the poor or homeless.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}];
